import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { obtenerProductos, guardarProducto } from '../services/productoService';

const STYLES = `
  @import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;600;700&family=Sora:wght@300;400;600;700&display=swap');
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
  body { background: #0d0f14; }

  .app-shell { display: flex; min-height: 100vh; font-family: 'Sora', sans-serif; color: #e8eaf0; background: #0d0f14; }

  /* ══ SIDEBAR ══ */
  .sidebar {
    width: 240px; min-width: 240px;
    background: #0b0d12; border-right: 1px solid #1a1d28;
    display: flex; flex-direction: column;
    position: fixed; top: 0; left: 0; bottom: 0; z-index: 100;
    transition: width .25s ease;
  }
  .sidebar.collapsed { width: 68px; min-width: 68px; }

  .sb-logo { display: flex; align-items: center; gap: 12px; padding: 20px 18px 16px; border-bottom: 1px solid #1a1d28; overflow: hidden; min-height: 72px; }
  .sb-logo img { width: 36px; height: 36px; object-fit: contain; border-radius: 8px; flex-shrink: 0; }
  .sb-logo-text { overflow: hidden; white-space: nowrap; }
  .sb-logo-name { font-size: 14px; font-weight: 700; color: #e8eaf0; line-height: 1.2; }
  .sb-logo-sub  { font-size: 11px; color: #4b5563; margin-top: 2px; font-family: 'JetBrains Mono', monospace; }

  .sb-user { display: flex; align-items: center; gap: 10px; padding: 14px 18px; border-bottom: 1px solid #1a1d28; overflow: hidden; }
  .sb-avatar { width: 32px; height: 32px; border-radius: 50%; flex-shrink: 0; display: flex; align-items: center; justify-content: center; font-size: 13px; font-weight: 700; }
  .sb-avatar.admin    { background: rgba(79,158,255,.18); color: #4f9eff; border: 1px solid rgba(79,158,255,.3); }
  .sb-avatar.vendedor { background: rgba(34,197,94,.18);  color: #22c55e; border: 1px solid rgba(34,197,94,.3); }
  .sb-user-info { overflow: hidden; white-space: nowrap; }
  .sb-user-name { font-size: 12px; font-weight: 600; color: #e8eaf0; }
  .sb-user-role { font-size: 10px; color: #6b7280; font-family: 'JetBrains Mono', monospace; text-transform: uppercase; letter-spacing: .5px; }

  .sb-nav { flex: 1; padding: 12px 10px; overflow-y: auto; overflow-x: hidden; }
  .sb-section-label { font-size: 10px; color: #374151; text-transform: uppercase; letter-spacing: 1.5px; padding: 8px 8px 4px; font-family: 'JetBrains Mono', monospace; white-space: nowrap; }

  .sb-item {
    display: flex; align-items: center; gap: 11px;
    padding: 10px 10px; border-radius: 8px; margin-bottom: 2px;
    cursor: pointer; border: none; background: transparent; width: 100%;
    text-align: left; color: #6b7280; font-family: 'Sora', sans-serif;
    font-size: 13px; font-weight: 500; white-space: nowrap; overflow: hidden;
    transition: background .15s, color .15s;
  }
  .sb-item:hover { background: #131720; color: #c9d1e0; }
  .sb-item.active { background: rgba(79,158,255,.12); color: #4f9eff; font-weight: 600; }
  .sb-icon  { font-size: 17px; flex-shrink: 0; width: 20px; text-align: center; }
  .sb-label { overflow: hidden; white-space: nowrap; flex: 1; }
  .sb-badge { background: #ef4444; color: #fff; font-size: 10px; font-weight: 700; padding: 1px 6px; border-radius: 20px; font-family: 'JetBrains Mono', monospace; flex-shrink: 0; }

  .sb-bottom { border-top: 1px solid #1a1d28; }
  .sb-logout .sb-item { color: #ef4444; }
  .sb-logout .sb-item:hover { background: rgba(239,68,68,.1); color: #f87171; }
  .sb-collapse { padding: 10px 12px; display: flex; justify-content: flex-end; border-top: 1px solid #1a1d28; }
  .sb-collapse-btn { width: 26px; height: 26px; border-radius: 6px; border: 1px solid #1e2230; background: #131720; color: #6b7280; cursor: pointer; font-size: 12px; display: flex; align-items: center; justify-content: center; transition: all .15s; }
  .sb-collapse-btn:hover { color: #e8eaf0; }

  /* ══ MAIN ══ */
  .main-content { margin-left: 240px; flex: 1; padding: 28px 32px; transition: margin-left .25s ease; min-width: 0; }
  .main-content.collapsed { margin-left: 68px; }

  .topbar { display: flex; justify-content: space-between; align-items: center; margin-bottom: 26px; gap: 16px; flex-wrap: wrap; }
  .topbar-title { font-size: 22px; font-weight: 700; letter-spacing: -.5px; }
  .topbar-title span { color: #4f9eff; }

  /* buttons */
  .btn { display: inline-flex; align-items: center; gap: 7px; padding: 9px 16px; border: none; border-radius: 8px; font-family: 'Sora', sans-serif; font-size: 13px; font-weight: 600; cursor: pointer; transition: all .18s; white-space: nowrap; }
  .btn:hover { filter: brightness(1.1); transform: translateY(-1px); }
  .btn.green  { background: #22c55e; color: #000; }
  .btn.orange { background: #f59e0b; color: #000; }
  .btn.blue   { background: #4f9eff; color: #000; }
  .btn.ghost  { background: #1e2230; color: #9ca3af; }

  /* tabs */
  .tabs { display: flex; gap: 4px; margin-bottom: 22px; border-bottom: 1px solid #1e2230; }
  .tab-btn { padding: 10px 20px; border: none; background: transparent; color: #6b7280; font-family: 'Sora', sans-serif; font-size: 13px; font-weight: 600; cursor: pointer; border-bottom: 2px solid transparent; margin-bottom: -1px; transition: all .15s; }
  .tab-btn.active { color: #4f9eff; border-bottom-color: #4f9eff; }
  .tab-btn:hover:not(.active) { color: #9ca3af; }

  /* stats */
  .stats-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(165px, 1fr)); gap: 13px; margin-bottom: 24px; }
  .stat-card { background: #131720; border: 1px solid #1e2230; border-radius: 12px; padding: 15px 18px; }
  .stat-label { font-size: 10px; color: #6b7280; text-transform: uppercase; letter-spacing: 1px; margin-bottom: 5px; font-family: 'JetBrains Mono', monospace; }
  .stat-val   { font-size: 22px; font-weight: 700; font-family: 'JetBrains Mono', monospace; }
  .c-blue { color: #4f9eff; } .c-red { color: #f87171; } .c-amber { color: #fbbf24; }

  /* search */
  .search-wrap { position: relative; margin-bottom: 18px; }
  .search-input { width: 100%; padding: 11px 16px 11px 42px; background: #131720; border: 1px solid #1e2230; border-radius: 10px; color: #e8eaf0; font-family: 'Sora', sans-serif; font-size: 13px; transition: border-color .2s; }
  .search-input:focus { outline: none; border-color: #4f9eff; }
  .search-input::placeholder { color: #4b5563; }
  .search-icon { position: absolute; left: 14px; top: 50%; transform: translateY(-50%); color: #4b5563; pointer-events: none; }

  /* form */
  .prod-form { background: #131720; border: 1px solid #1e2230; border-radius: 13px; padding: 20px; margin-bottom: 22px; }
  .prod-form.editing { border-color: rgba(245,158,11,.3); background: #18140a; }
  .prod-form-title { font-size: 14px; font-weight: 700; margin-bottom: 14px; }
  .prod-form-grid  { display: flex; flex-wrap: wrap; gap: 10px; }
  .inp { padding: 9px 13px; background: #0d0f14; border: 1px solid #1e2230; border-radius: 8px; color: #e8eaf0; font-family: 'Sora', sans-serif; font-size: 13px; transition: border-color .18s; }
  .inp:focus { outline: none; border-color: #4f9eff; }
  .inp::placeholder { color: #4b5563; }
  .inp.flex1 { flex: 1; min-width: 130px; }

  /* table */
  .tbl-wrap { overflow-x: auto; border-radius: 12px; border: 1px solid #1e2230; }
  .tbl { width: 100%; border-collapse: collapse; }
  .tbl thead tr { background: #131720; }
  .tbl th { padding: 12px 15px; text-align: left; font-size: 10px; font-family: 'JetBrains Mono', monospace; text-transform: uppercase; letter-spacing: 1px; color: #6b7280; border-bottom: 1px solid #1e2230; white-space: nowrap; }
  .tbl td { padding: 11px 15px; border-bottom: 1px solid #0f1117; font-size: 13px; }
  .tbl tbody tr:hover { background: #111420; }
  .tbl tbody tr:last-child td { border-bottom: none; }
  .mono { font-family: 'JetBrains Mono', monospace; }

  .stock-badge { display: inline-flex; align-items: center; gap: 5px; padding: 3px 9px; border-radius: 20px; font-size: 11px; font-weight: 600; font-family: 'JetBrains Mono', monospace; }
  .stock-badge.ok       { background: rgba(34,197,94,.1);  color: #22c55e; border: 1px solid rgba(34,197,94,.25); }
  .stock-badge.low      { background: rgba(251,191,36,.1); color: #fbbf24; border: 1px solid rgba(251,191,36,.25); }
  .stock-badge.critical { background: rgba(239,68,68,.1);  color: #ef4444; border: 1px solid rgba(239,68,68,.25); }

  .stock-row { display: flex; align-items: center; gap: 7px; }
  .stock-inp { width: 65px; padding: 4px 8px; background: #0d0f14; border: 1px solid #4f9eff; border-radius: 6px; color: #4f9eff; font-family: 'JetBrains Mono', monospace; font-size: 13px; font-weight: 600; }
  .stock-inp:focus { outline: none; box-shadow: 0 0 0 2px rgba(79,158,255,.2); }
  .ico-btn { width: 26px; height: 26px; border: none; border-radius: 6px; cursor: pointer; display: flex; align-items: center; justify-content: center; font-size: 13px; transition: all .15s; }
  .ico-btn.save   { background: rgba(34,197,94,.15); color: #22c55e; }
  .ico-btn.save:hover   { background: rgba(34,197,94,.28); }
  .ico-btn.cancel { background: rgba(239,68,68,.12); color: #ef4444; }
  .ico-btn.cancel:hover { background: rgba(239,68,68,.22); }
  .ico-btn.edit   { background: rgba(79,158,255,.12); color: #4f9eff; }
  .ico-btn.edit:hover   { background: rgba(79,158,255,.22); }

  .profit-pill { display: inline-flex; padding: 2px 8px; border-radius: 20px; font-size: 11px; font-weight: 700; font-family: 'JetBrains Mono', monospace; }
  .profit-pill.pos { background: rgba(34,197,94,.1); color: #22c55e; }

  /* costos */
  .costos-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(195px, 1fr)); gap: 14px; margin-bottom: 24px; }
  .costo-card { background: #131720; border: 1px solid #1e2230; border-radius: 12px; padding: 20px; position: relative; overflow: hidden; }
  .costo-card::before { content: ''; position: absolute; top: 0; left: 0; right: 0; height: 3px; }
  .costo-card.total::before     { background: linear-gradient(90deg, #4f9eff, #818cf8); }
  .costo-card.invertido::before { background: linear-gradient(90deg, #f87171, #fb923c); }
  .costo-card.alertas::before   { background: linear-gradient(90deg, #fbbf24, #f59e0b); }
  .costo-icon  { font-size: 26px; margin-bottom: 10px; }
  .costo-label { font-size: 10px; color: #6b7280; text-transform: uppercase; letter-spacing: 1px; margin-bottom: 4px; font-family: 'JetBrains Mono', monospace; }
  .costo-value { font-size: 26px; font-weight: 700; font-family: 'JetBrains Mono', monospace; }
  .costo-sub   { font-size: 11px; color: #6b7280; margin-top: 4px; }
  .section-title { font-size: 11px; font-weight: 700; margin-bottom: 12px; color: #6b7280; text-transform: uppercase; letter-spacing: 1px; font-family: 'JetBrains Mono', monospace; }

  /* modal */
  .modal-overlay { position: fixed; inset: 0; background: rgba(0,0,0,.75); z-index: 200; display: flex; align-items: center; justify-content: center; }
  .modal-box { background: #131720; border: 1px solid #1e2230; border-radius: 16px; padding: 26px; width: 350px; max-width: 92vw; }
  .modal-title { font-size: 16px; font-weight: 700; margin-bottom: 16px; }
  .modal-label { font-size: 11px; color: #9ca3af; margin-bottom: 6px; font-family: 'JetBrains Mono', monospace; text-transform: uppercase; letter-spacing: 1px; }
  .modal-actions { display: flex; gap: 10px; margin-top: 18px; justify-content: flex-end; }
`;

const stockStatus = (stock, limit) => stock === 0 ? 'critical' : stock <= limit ? 'low' : 'ok';
const stockLabel  = { ok: '✅', low: '⚠️', critical: '🔴' };

const Inventario = () => {
  const navigate = useNavigate();

  const [productos, setProductos]   = useState([]);
  const [busqueda, setBusqueda]     = useState('');
  const [editandoId, setEditandoId] = useState(null);
  const [nuevoProd, setNuevoProd]   = useState({ codigo:'', nombre:'', stock:0, precioCompra:0, precioVenta:0, categoria:'Fundas' });

  const [editandoStockId, setEditandoStockId] = useState(null);
  const [nuevoStock, setNuevoStock]           = useState('');

  const [limiteStock, setLimiteStock] = useState(() => parseInt(localStorage.getItem('limiteStock') || '5'));
  const [modalLimite, setModalLimite] = useState(false);
  const [limiteTemp, setLimiteTemp]   = useState('');

  const [tab, setTab]           = useState('inventario');
  const [collapsed, setCollapsed] = useState(false);

  const matricula = localStorage.getItem('usuarioLogueado') || 'desconocido';
  const rol       = localStorage.getItem('rolUsuario') || 'VENDEDOR';
  const esAdmin   = rol === 'ADMIN';

  useEffect(() => {
    if (!localStorage.getItem('usuarioLogueado')) {
      alert('⚠️ Acceso denegado. Por favor, inicia sesión.');
      navigate('/');
    } else { cargarProductos(); }
  }, [navigate]);

  const cargarProductos = async () => { const d = await obtenerProductos(); setProductos(d); };

  const productosFiltrados = productos.filter(p =>
    p.nombre.toLowerCase().includes(busqueda.toLowerCase()) ||
    p.codigo.toLowerCase().includes(busqueda.toLowerCase())
  );

  const handleGuardar = async (e) => {
    e.preventDefault(); if (!esAdmin) return;
    await guardarProducto({ ...nuevoProd, id: editandoId, registradoPorMatricula: matricula });
    alert(editandoId ? '✅ Producto actualizado' : '✅ Producto guardado');
    setNuevoProd({ codigo:'', nombre:'', stock:0, precioCompra:0, precioVenta:0, categoria:'Fundas' });
    setEditandoId(null); cargarProductos();
  };

  const prepararEdicion = (p) => {
    setEditandoId(p.id);
    setNuevoProd({ codigo:p.codigo, nombre:p.nombre, stock:p.stock, precioCompra:p.precioCompra, precioVenta:p.precioVenta, categoria:p.categoria });
  };

  const iniciarEditStock    = (p) => { setEditandoStockId(p.id); setNuevoStock(String(p.stock)); };
  const guardarStockInline  = async (p) => {
    const n = parseInt(nuevoStock);
    if (isNaN(n) || n < 0) { alert('Stock inválido'); return; }
    await guardarProducto({ ...p, stock: n, registradoPorMatricula: matricula });
    setEditandoStockId(null); cargarProductos();
  };

  const guardarLimite = () => {
    const v = parseInt(limiteTemp);
    if (isNaN(v) || v < 0) { alert('Valor inválido'); return; }
    setLimiteStock(v); localStorage.setItem('limiteStock', v); setModalLimite(false);
  };

  const handleLogout = () => {
    localStorage.removeItem('usuarioLogueado');
    localStorage.removeItem('rolUsuario');
    navigate('/');
  };

  const totalProductos = productos.length;
  const totalUnidades  = productos.reduce((s,p) => s + p.stock, 0);
  const totalInvertido = productos.reduce((s,p) => s + p.precioCompra * p.stock, 0);
  const bajoStock      = productos.filter(p => p.stock <= limiteStock).length;

  return (
    <>
      <style>{STYLES}</style>
      <div className="app-shell">

        {/* ══════════ SIDEBAR ══════════ */}
        <aside className={`sidebar ${collapsed ? 'collapsed' : ''}`}>

          {/* Logo */}
          <div className="sb-logo">
            <img src="/logo.png" alt="logo" />
            {!collapsed && (
              <div className="sb-logo-text">
                <div className="sb-logo-name">Isla Tecnológica</div>
                <div className="sb-logo-sub">Sistema POS</div>
              </div>
            )}
          </div>

          {/* Usuario */}
          <div className="sb-user">
            <div className={`sb-avatar ${esAdmin ? 'admin' : 'vendedor'}`}>
              {matricula.charAt(0).toUpperCase()}
            </div>
            {!collapsed && (
              <div className="sb-user-info">
                <div className="sb-user-name">{matricula}</div>
                <div className="sb-user-role">{esAdmin ? '🔑 Admin' : '👤 Vendedor'}</div>
              </div>
            )}
          </div>

          {/* Nav */}
          <nav className="sb-nav">
            {!collapsed && <div className="sb-section-label">Principal</div>}

            <button className={`sb-item ${tab==='inventario' ? 'active' : ''}`} onClick={() => setTab('inventario')} title={collapsed ? 'Inventario' : ''}>
              <span className="sb-icon">📦</span>
              {!collapsed && <span className="sb-label">Inventario</span>}
              {!collapsed && bajoStock > 0 && <span className="sb-badge">{bajoStock}</span>}
            </button>

            {esAdmin && (
              <button className={`sb-item ${tab==='costos' ? 'active' : ''}`} onClick={() => setTab('costos')} title={collapsed ? 'Costos' : ''}>
                <span className="sb-icon">💰</span>
                {!collapsed && <span className="sb-label">Costos & Capital</span>}
              </button>
            )}

            <button className="sb-item" onClick={() => navigate('/ventas')} title={collapsed ? 'Ventas' : ''}>
              <span className="sb-icon">🛒</span>
              {!collapsed && <span className="sb-label">Ventas</span>}
            </button>

            {esAdmin && (
              <>
                <button className="sb-item" onClick={() => navigate('/reportes')} title={collapsed ? 'Ganancias' : ''}>
                  <span className="sb-icon">📈</span>
                  {!collapsed && <span className="sb-label">Ganancias</span>}
                </button>
                <button className="sb-item" onClick={() => navigate('/usuarios')} title={collapsed ? 'Usuarios' : ''}>
                  <span className="sb-icon">👥</span>
                  {!collapsed && <span className="sb-label">Usuarios</span>}
                </button>
              </>
            )}

            {esAdmin && (
              <>
                {!collapsed && <div className="sb-section-label" style={{marginTop:10}}>Configuración</div>}
                <button className="sb-item" onClick={() => { setLimiteTemp(String(limiteStock)); setModalLimite(true); }} title={collapsed ? 'Límite Stock' : ''}>
                  <span className="sb-icon">⚙️</span>
                  {!collapsed && <span className="sb-label">Límite Stock</span>}
                </button>
              </>
            )}
          </nav>

          {/* Bottom */}
          <div className="sb-bottom">
            <div className="sb-logout" style={{padding:'10px'}}>
              <button className="sb-item" onClick={handleLogout} title={collapsed ? 'Cerrar Sesión' : ''}>
                <span className="sb-icon">🚪</span>
                {!collapsed && <span className="sb-label">Cerrar Sesión</span>}
              </button>
            </div>
            <div className="sb-collapse">
              <button className="sb-collapse-btn" onClick={() => setCollapsed(c => !c)}>
                {collapsed ? '▶' : '◀'}
              </button>
            </div>
          </div>
        </aside>

        {/* ══════════ MAIN ══════════ */}
        <main className={`main-content ${collapsed ? 'collapsed' : ''}`}>

          {/* Topbar */}
          <div className="topbar">
            <div className="topbar-title">
              {tab === 'inventario' && <><span>Inventario</span> de Productos</>}
              {tab === 'costos'     && <><span>Costos</span> & Capital</>}
            </div>
            {tab === 'inventario' && bajoStock > 0 && (
              <div style={{fontSize:13, color:'#fbbf24', display:'flex', alignItems:'center', gap:6}}>
                ⚠️ <strong>{bajoStock}</strong> productos con stock bajo (≤{limiteStock})
              </div>
            )}
          </div>

          {/* Stats */}
          {esAdmin && (
            <div className="stats-grid">
              <div className="stat-card"><div className="stat-label">Productos</div><div className="stat-val c-blue">{totalProductos}</div></div>
              <div className="stat-card"><div className="stat-label">Unidades Totales</div><div className="stat-val c-blue">{totalUnidades}</div></div>
              <div className="stat-card"><div className="stat-label">Capital Invertido</div><div className="stat-val c-red">${totalInvertido.toFixed(2)}</div></div>
              <div className="stat-card"><div className="stat-label">Bajo Stock</div><div className="stat-val c-amber">{bajoStock} prods</div></div>
            </div>
          )}

          {/* Tabs */}
          {esAdmin && (
            <div className="tabs">
              <button className={`tab-btn ${tab==='inventario'?'active':''}`} onClick={() => setTab('inventario')}>📦 Inventario</button>
              <button className={`tab-btn ${tab==='costos'?'active':''}`} onClick={() => setTab('costos')}>💰 Costos & Capital</button>
            </div>
          )}

          {/* ── INVENTARIO ── */}
          {tab === 'inventario' && (
            <>
              {esAdmin && (
                <div className={`prod-form ${editandoId ? 'editing' : ''}`}>
                  <div className="prod-form-title">{editandoId ? '✏️ Editando Producto' : '➕ Agregar Nuevo Producto'}</div>
                  <form onSubmit={handleGuardar}>
                    <div className="prod-form-grid">
                      <input className="inp" placeholder="Código" value={nuevoProd.codigo} onChange={e => setNuevoProd({...nuevoProd, codigo:e.target.value})} required />
                      <input className="inp flex1" placeholder="Nombre" value={nuevoProd.nombre} onChange={e => setNuevoProd({...nuevoProd, nombre:e.target.value})} required />
                      <input className="inp" style={{width:85}} type="number" placeholder="Stock" value={nuevoProd.stock} onChange={e => setNuevoProd({...nuevoProd, stock:parseInt(e.target.value)})} required />
                      <input className="inp" style={{width:120}} type="number" step="0.01" placeholder="Costo $" value={nuevoProd.precioCompra} onChange={e => setNuevoProd({...nuevoProd, precioCompra:parseFloat(e.target.value)})} required />
                      <input className="inp" style={{width:120}} type="number" step="0.01" placeholder="Venta $" value={nuevoProd.precioVenta} onChange={e => setNuevoProd({...nuevoProd, precioVenta:parseFloat(e.target.value)})} required />
                    </div>
                    <div style={{display:'flex', gap:10, marginTop:14}}>
                      <button type="submit" className={`btn ${editandoId?'orange':'green'}`}>{editandoId ? 'Actualizar' : 'Guardar'}</button>
                      {editandoId && <button type="button" className="btn ghost" onClick={() => { setEditandoId(null); setNuevoProd({codigo:'',nombre:'',stock:0,precioCompra:0,precioVenta:0,categoria:'Fundas'}); }}>Cancelar</button>}
                    </div>
                  </form>
                </div>
              )}

              <div className="search-wrap">
                <span className="search-icon">🔍</span>
                <input className="search-input" placeholder="Buscar por nombre o código..." value={busqueda} onChange={e => setBusqueda(e.target.value)} />
              </div>

              <div className="tbl-wrap">
                <table className="tbl">
                  <thead>
                    <tr>
                      <th>Código</th><th>Nombre</th><th>Stock</th>
                      {esAdmin && <th>Costo</th>}
                      <th>Venta</th>
                      {esAdmin && <th>Gan. Unit.</th>}
                      {esAdmin && <th>Val. Stock</th>}
                      {esAdmin && <th>Acciones</th>}
                    </tr>
                  </thead>
                  <tbody>
                    {productosFiltrados.map(p => {
                      const st = stockStatus(p.stock, limiteStock);
                      const editing = editandoStockId === p.id;
                      return (
                        <tr key={p.id}>
                          <td><span className="mono" style={{color:'#6b7280'}}>{p.codigo}</span></td>
                          <td style={{fontWeight:500}}>{p.nombre}</td>
                          <td>
                            {editing ? (
                              <div className="stock-row">
                                <input className="stock-inp" type="number" min="0" value={nuevoStock} autoFocus
                                  onChange={e => setNuevoStock(e.target.value)}
                                  onKeyDown={e => { if(e.key==='Enter') guardarStockInline(p); if(e.key==='Escape') setEditandoStockId(null); }} />
                                <button className="ico-btn save"   onClick={() => guardarStockInline(p)}>✓</button>
                                <button className="ico-btn cancel" onClick={() => setEditandoStockId(null)}>✕</button>
                              </div>
                            ) : (
                              <div className="stock-row">
                                <span className={`stock-badge ${st}`}>{stockLabel[st]} {p.stock}</span>
                                {esAdmin && <button className="ico-btn edit" onClick={() => iniciarEditStock(p)}>✎</button>}
                              </div>
                            )}
                          </td>
                          {esAdmin && <td className="mono" style={{color:'#f87171'}}>${p.precioCompra.toFixed(2)}</td>}
                          <td className="mono">${p.precioVenta.toFixed(2)}</td>
                          {esAdmin && <td><span className="profit-pill pos">+${(p.precioVenta-p.precioCompra).toFixed(2)}</span></td>}
                          {esAdmin && <td className="mono" style={{color:'#4f9eff'}}>${(p.precioCompra*p.stock).toFixed(2)}</td>}
                          {esAdmin && <td><button className="btn blue" style={{padding:'5px 12px',fontSize:12}} onClick={() => prepararEdicion(p)}>Editar</button></td>}
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            </>
          )}

          {/* ── COSTOS ── */}
          {tab === 'costos' && esAdmin && (
            <>
              <div className="costos-grid">
                <div className="costo-card total">
                  <div className="costo-icon">📦</div>
                  <div className="costo-label">Total Productos</div>
                  <div className="costo-value c-blue">{totalProductos}</div>
                  <div className="costo-sub">{totalUnidades} unidades en stock</div>
                </div>
                <div className="costo-card invertido">
                  <div className="costo-icon">💸</div>
                  <div className="costo-label">Capital Invertido</div>
                  <div className="costo-value c-red">${totalInvertido.toFixed(2)}</div>
                  <div className="costo-sub">Costo total del inventario actual</div>
                </div>
                <div className="costo-card alertas">
                  <div className="costo-icon">⚠️</div>
                  <div className="costo-label">Bajo Stock</div>
                  <div className="costo-value c-amber">{bajoStock}</div>
                  <div className="costo-sub">Productos con ≤{limiteStock} unidades</div>
                </div>
              </div>

              <div className="section-title">📋 Desglose por Producto</div>
              <div className="tbl-wrap">
                <table className="tbl">
                  <thead>
                    <tr>
                      <th>Código</th><th>Producto</th><th>Stock</th>
                      <th>Costo Unit.</th><th>Capital en Stock</th><th>Precio Venta</th>
                    </tr>
                  </thead>
                  <tbody>
                    {[...productos].sort((a,b) => (b.precioCompra*b.stock)-(a.precioCompra*a.stock)).map(p => (
                      <tr key={p.id}>
                        <td><span className="mono" style={{color:'#6b7280'}}>{p.codigo}</span></td>
                        <td style={{fontWeight:500}}>{p.nombre}</td>
                        <td><span className={`stock-badge ${stockStatus(p.stock,limiteStock)}`}>{p.stock}</span></td>
                        <td className="mono" style={{color:'#f87171'}}>${p.precioCompra.toFixed(2)}</td>
                        <td className="mono" style={{color:'#f87171',fontWeight:600}}>${(p.precioCompra*p.stock).toFixed(2)}</td>
                        <td className="mono">${p.precioVenta.toFixed(2)}</td>
                      </tr>
                    ))}
                  </tbody>
                  <tfoot>
                    <tr style={{background:'#0d0f14', borderTop:'2px solid #1e2230'}}>
                      <td colSpan={4} style={{padding:'13px 15px', fontWeight:700, fontSize:13}}>TOTAL INVERTIDO</td>
                      <td className="mono" style={{color:'#f87171', fontWeight:700, padding:'13px 15px'}}>${totalInvertido.toFixed(2)}</td>
                      <td></td>
                    </tr>
                  </tfoot>
                </table>
              </div>
            </>
          )}
        </main>
      </div>

      {/* ── MODAL LÍMITE ── */}
      {modalLimite && (
        <div className="modal-overlay" onClick={() => setModalLimite(false)}>
          <div className="modal-box" onClick={e => e.stopPropagation()}>
            <div className="modal-title">⚙️ Configurar Límite de Stock Bajo</div>
            <p style={{fontSize:13, color:'#9ca3af', marginBottom:16, lineHeight:1.6}}>
              Productos con stock igual o menor a este número se marcarán como bajo stock o crítico.
            </p>
            <div className="modal-label">Límite mínimo de unidades</div>
            <input className="inp" style={{width:'100%'}} type="number" min="0" value={limiteTemp}
              onChange={e => setLimiteTemp(e.target.value)} placeholder={`Actual: ${limiteStock}`} autoFocus />
            <div style={{fontSize:12, color:'#6b7280', marginTop:8}}>
              💡 Ej: 5 → productos con ≤5 unidades se marcan como bajo stock.
            </div>
            <div className="modal-actions">
              <button className="btn ghost" onClick={() => setModalLimite(false)}>Cancelar</button>
              <button className="btn green" onClick={guardarLimite}>Guardar</button>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

export default Inventario;
